select v_1 as "supp_nation", v_2 as "cust_nation", v_3 as "l_year", v_4 as "revenue" from (select v_5 as v_1, v_6 as v_2, v_7 as v_3, sum(v_8) as v_4 from (select v_5, v_6, cast(strftime('%Y', v_9) as integer) as v_7, v_10 * (1 - v_11) as v_8 from (select * from (select * from (select * from (select * from (select * from (select * from (select "s_suppkey" as v_12, "s_name" as v_13, "s_address" as v_14, "s_nationkey" as v_15, "s_phone" as v_16, "s_acctbal" as v_17, "s_comment" as v_18 from "supplier") l inner join (select * from (select "l_orderkey" as v_19, "l_partkey" as v_20, "l_suppkey" as v_21, "l_linenumber" as v_22, "l_quantity" as v_23, "l_extendedprice" as v_10, "l_discount" as v_11, "l_tax" as v_24, "l_returnflag" as v_25, "l_linestatus" as v_26, "l_shipdate" as v_9, "l_commitdate" as v_27, "l_receiptdate" as v_28, "l_shipinstruct" as v_29, "l_shipmode" as v_30, "l_comment" as v_31 from "lineitem") s where v_9 between (date('1995-01-01', '+0 seconds')) and (date('1996-12-31', '+0 seconds'))) r on v_12 = v_21) l inner join (select "o_orderkey" as v_32, "o_custkey" as v_33, "o_orderstatus" as v_34, "o_totalprice" as v_35, "o_orderdate" as v_36, "o_orderpriority" as v_37, "o_clerk" as v_38, "o_shippriority" as v_39, "o_comment" as v_40 from "orders") r on v_32 = v_19) l inner join (select "c_custkey" as v_41, "c_name" as v_42, "c_address" as v_43, "c_nationkey" as v_44, "c_phone" as v_45, "c_acctbal" as v_46, "c_mktsegment" as v_47, "c_comment" as v_48 from "customer") r on v_41 = v_33) l inner join (select "n_nationkey" as v_49, "n_name" as v_5, "n_regionkey" as v_50, "n_comment" as v_51 from "nation") r on v_15 = v_49) l inner join (select "n_nationkey" as v_52, "n_name" as v_6, "n_regionkey" as v_53, "n_comment" as v_54 from "nation") r on v_44 = v_52) s where ((v_5 = 'FRANCE') and (v_6 = 'GERMANY')) or ((v_5 = 'GERMANY') and (v_6 = 'FRANCE'))) s) s group by 1, 2, 3) s order by v_1, v_2, v_3
